(* generate heap *)

size := SHR(size,2);
size2 := UINT_TO_INT(SHR(size,1));
FOR i := SIZE2  TO 1 BY -1 DO 		(* zweite Hälfte des Feldes braucht nicht betrachtet werden *)
	j:=i;
    WHILE j <= SIZE2 DO
     	stop := j * 2 + 1;               (* finde Maximum der (beiden) Söhne *)
        IF stop > UINT_TO_INT(SIZE) THEN stop := stop - 1;
        ELSIF pt^[stop-1] > pt^[stop] THEN stop := stop - 1;
		END_IF;
        IF pt^[j] < pt^[stop] THEN   		(* ggf. tauschen *)
         	temp := pt^[j];
            pt^[j] := pt^[stop];
            pt^[stop] := temp;
        END_IF;
        j := stop;
    END_WHILE;
END_FOR;

(* heapsort *)
FOR heapsize := UINT_TO_INT(size) TO 1 BY -1 DO
	popmax := pt^[1];
	pt^[1] := pt^[heapsize];
   	i := 1;
	hs2 := SHR(heapsize,1);
	WHILE i <= hs2 DO	     (* letztes Element an Anfang setzen und versickern lassen *)
       	stop := i * 2 + 1;                (* finde Maximum der (beiden) Söhne *)
        	IF stop > heapsize THEN stop := stop - 1;
        	ELSIF pt^[stop-1] > pt^[stop] THEN stop := stop - 1;
	 	END_IF;
        	IF pt^[i] < pt^[stop] THEN	     (* ggf. tauschen *)
            		temp := pt^[i];
            		pt^[i] := pt^[stop];
            		pt^[stop] := temp;
        	END_IF;
        	i := stop;
    	END_WHILE;
	pt^[heapsize] := popmax;
END_FOR;

_ARRAY_SORT := TRUE;

(* old algorithm bubble sort used before rev 1.2
