tx := T_PLC_MS();
IF E AND init THEN
	(* we need to set tl = tx when direction changes *)
	IF dir XOR last_dir THEN
	 tl := tx;
	 last_dir := dir;
	END_IF;
	(* check_elapsed time and calculate only if necessary *)
	IF tr > t#0s THEN
		step := DWORD_TO_INT(SHL(tx-tl, 8) / TIME_TO_DWORD(TR));
	ELSE
		step := 255;
	END_IF;
	IF step > 0 THEN
		(* perform the step on the ramp *)
		tl := tx;
		(* calculate the step response *)
		IF NOT dir THEN step := - step; END_IF;
		rmp := INT_TO_BYTE(LIMIT(0, BYTE_TO_INT(rmp) + step, 255));
	END_IF;
ELSE
	tl := tx;
	init := TRUE;
END_IF;


