ps := ADR(str);
lx := LEN(str);
end := UINT_TO_INT(size) - lx;
lx := lx - 1;
FOR i := pos TO end DO
	FOR k := 0 TO lx DO
		IF (ps^[k] <> ign) AND (ps^[k] <> pt^[i+k]) THEN EXIT; END_IF;
	END_FOR;
	IF k > lx THEN
		BUFFER_SEARCH := i;
		RETURN;
	END_IF;
END_FOR;
BUFFER_SEARCH := 0;


(* revision History

hm 5. mar. 2008	rev 1.0
	original version

hm	16. mar. 2008	rev 1.1
	chaged type of input size to uint

hm	13. may. 2008	rev 1.2
	changed type of pointer to array[1..32767]
	changed size of string to STRING_LENGTH

