	init := TRUE;
	DTS := Start;
	tc := 0;
	last := tx;
ELSIF tc >= 1000 THEN
	td := (tc / 1000)*1000;
	DTS := DTS + DWORD_TO_TIME(td);
	last := last + REAL_TO_DWORD(DWORD_TO_REAL(td) / speed);
END_IF;

