IF rst THEN
	(* asynchronous reset for the fifo *)
	NW := NR := 0;
	Dout := 0;
	empty := TRUE;
	full := FALSE;
ELSIF E THEN
	IF WR AND NOT full THEN
		(* write action *)
		fifo[NW] := Din;
		NW := INC1(NW, 16);
		full := NW = NR;
		empty := FALSE;
	ELSIF NOT WR AND NOT empty THEN
		(* read from stack *)
		Dout := fifo[NR];
		NR := INC1(NR, 16);
		empty := NR = NW;
		full := FALSE;
	END_IF
END_IF;

