(* berechnung von ostern für das aktuelle jahr *)
jahr := YEAR_OF_DATE(date_in);
ostern := EASTER(jahr);
last_active := DATE_IN;
wdx := DAY_OF_WEEK(DATE_IN);

(* check array if today is holiday *)
Y := (wdx = 5 AND FRIDAY) OR (wdx = 6 AND SATURDAY) OR (wdx = 7 AND SUNDAY);
NAME := '';

FOR i := 0 TO size DO
	check := location.HOLIDAY[cx, i];
	x_date := SET_DATE(jahr, check.MONTH , check.DAY);
	IF check.USE = 1 AND check.MONTH > 0 THEN
		(* check for fixed date holiday *)
		IF x_date = date_in THEN
			Y := TRUE;
			NAME := check.NAME;
			RETURN;
		END_IF;
	ELSIF check.USE = 1 AND check.MONTH = 0 THEN
		(* check for holiday in reference to easter *)
		IF DATE_ADD(ostern, check.DAY ,0,0,0) = date_in THEN
			Y := TRUE;
			NAME := check.NAME;
			RETURN;
		END_IF;
	ELSIF check.USE < 0 THEN
		(* check for holiday on a weekday before date *)
		IF DAY_OF_WEEK(date_in) = ABS(check.USE) AND date_in < x_date AND date_in >= DATE_ADD(x_date,-7,0,0,0) THEN
			Y := TRUE;
			NAME := check.NAME;
			RETURN;
		END_IF;
	END_IF;
END_FOR;



