IF rst THEN
	(* asynchronous reset for the fifo *)
	N := -1;
	Dout := 0;
	empty := TRUE;
	full := FALSE;
ELSIF E THEN
	IF RW AND NOT full THEN
		(* write action *)
		N := N + 1;
		full := N = TOP;
		empty := FALSE;
		stack[N] := Din;
	ELSIF NOT RW AND NOT empty THEN
		(* read from stack *)
		Dout := stack[N];
		N := N - 1;
		empty := N < 0;
		full := FALSE;
	END_IF;
END_IF;


