(* check if string is empty and return empty url *)
IF STR = '' THEN RETURN; END_IF;

(* extract the protocol *)
(* first we check if the optional protocol is specified ending with a :// *)
pos := FIND(STR, '://');
IF pos > 0 THEN
	(* store protocol and restore the rest of url in temp *)
	STRING_TO_URL.PROTOCOL := LEFT(STR, pos - 1);
	STRING_TO_URL.DOMAIN := RIGHT(STR, LEN(STR) - pos - 2);
ELSE
	STRING_TO_URL.DOMAIN := STR;
	STRING_TO_URL.PROTOCOL := DEFAULT_PROTOCOL;
END_IF;

(* extract user and password if present ending with a @ *)
pos := FIND(STRING_TO_URL.DOMAIN, '@');
IF pos > 0 THEN
	(* extract user *)
	pos2 := FIND(STRING_TO_URL.DOMAIN,':')+1;
	IF pos2 > 1 AND pos2 <= pos THEN
		STRING_TO_URL.USER := LEFT(STRING_TO_URL.DOMAIN,pos2 - 2);
		STRING_TO_URL.PASSWORD := MID(STRING_TO_URL.DOMAIN, pos - pos2, pos2);
	ELSE
		STRING_TO_URL.USER := LEFT(STRING_TO_URL.DOMAIN, pos - 2);
		STRING_TO_URL.PASSWORD := '';
	END_IF;
	STRING_TO_URL.DOMAIN := RIGHT(STRING_TO_URL.DOMAIN, LEN(STRING_TO_URL.DOMAIN) - pos);
ELSE
	STRING_TO_URL.USER := '';
	STRING_TO_URL.PASSWORD := '';
END_IF;

(* extract anchor *)
pos := FIND(STRING_TO_URL.DOMAIN, '#');
IF pos > 0 THEN
	STRING_TO_URL.ANCHOR := RIGHT(STRING_TO_URL.DOMAIN, LEN(STRING_TO_URL.DOMAIN) - pos);
	STRING_TO_URL.DOMAIN := LEFT(STRING_TO_URL.DOMAIN, pos - 1);
ELSE
	STRING_TO_URL.ANCHOR := '';
END_IF;

(* extract query  *)
pos := FIND(STRING_TO_URL.DOMAIN, '?');
IF pos > 0 THEN
	STRING_TO_URL.QUERY := RIGHT(STRING_TO_URL.DOMAIN, LEN(STRING_TO_URL.DOMAIN) - pos);
	STRING_TO_URL.DOMAIN := LEFT(STRING_TO_URL.DOMAIN, pos - 1);
ELSE
	STRING_TO_URL.QUERY := '';
END_IF;

(* extract path  *)
pos := FIND(STRING_TO_URL.DOMAIN, '/');
IF pos > 0 THEN
	STRING_TO_URL.PATH := RIGHT(STRING_TO_URL.DOMAIN, LEN(STRING_TO_URL.DOMAIN) - pos + 1);
	STRING_TO_URL.DOMAIN := LEFT(STRING_TO_URL.DOMAIN, pos - 1);
ELSE
	STRING_TO_URL.PATH := DEFAULT_PATH;
END_IF;

(* extract port and leave domain *)
pos := FIND(STRING_TO_URL.DOMAIN, ':');
IF pos > 0 THEN
	STRING_TO_URL.PORT := STRING_TO_WORD(RIGHT(STRING_TO_URL.DOMAIN, LEN(STRING_TO_URL.DOMAIN) - pos));
	STRING_TO_URL.DOMAIN := LEFT(STRING_TO_URL.DOMAIN, pos - 1);
ELSE
	STRING_TO_URL.PORT := 0;
END_IF;




