(* for performance reasons we only execute the code at the beginning of a new second
	we cannot compare the dtime directly because a daylight savings time switch might have happened
	therefore we need to compare the seconds and minutes of the dtime only 
	if we would compare seconds only the module would be in troulbe when its only called every minute 
	with this code the module is called every start of a new second *)

IF RST THEN
	last_execute := DT#1970-1-1-00:00;
	FOR pos := 0 TO ARRAY_MAX DO
		IF (PROG[pos].CHANNEL >= OFS) AND (PROG[pos].CHANNEL < (OFS + 4)) THEN PROG[pos].LAST := 0; END_IF;
	END_FOR;
ELSIF dtime <> last_execute THEN
	(* prepare the logical input mask to be used later *)
	mask := 255;
	mask.0 := L0;
	mask.1 := L1;
	mask.2 := L2;
	mask.3 := L3;
	(* save the actual second for next execution test *)
	last_execute := DTIME;
	current_day := DINT_TO_DWORD(DAY_OF_DATE(DT_TO_DATE(Dtime)));
	FOR pos := 0 TO ARRAY_MAX DO
		event := prog[pos];
		channel := event.CHANNEL - OFS;
		IF (event.TYP > 0) AND (channel >= 0) AND (channel <= channel_max) THEN
			ma[channel] := event.LAND;
			mo[channel] := event.LOR;
			CASE event.TYP OF
				1:	(* daily event *)
					qn[channel] := (DT_TO_TOD(dtime) >= event.START) AND (DT_TO_TOD(dtime) < event.START + event.DURATION);
					prog[pos].LAST := current_day;
				2: 	(* event by selected weekdays *)
					qn[channel] := (DT_TO_TOD(dtime) >= event.START) AND (DT_TO_TOD(dtime) < event.START + event.DURATION) AND ((SHR(BYTE#128, DAY_OF_WEEK(DT_TO_DATE(Dtime))) AND event.DAY) > 0);
					prog[pos].LAST := current_day;
				3:	(* event every N days *)
					qn[channel] := (DT_TO_TOD(dtime) >= event.START) AND (DT_TO_TOD(dtime) < event.START + event.DURATION) AND (event.LAST + event.DAY >= current_day);
					prog[pos].LAST := current_day;
				10:	(* weekly event exactly once a week the weekday is specified in day, 1= mo *)
					qn[channel] := (DT_TO_TOD(dtime) >= event.START) AND (DT_TO_TOD(dtime) < event.START + event.DURATION) AND DAY_OF_WEEK(DT_TO_DATE(DTIME)) = BYTE_TO_INT(event.DAY);
					prog[pos].LAST := current_day;
				20:	(* monthly event *)
					qn[channel] := (DT_TO_TOD(dtime) >= event.START) AND (DT_TO_TOD(dtime) < event.START + event.DURATION) AND DAY_OF_MONTH(DT_TO_DATE(DTIME)) = BYTE_TO_INT(event.DAY);
					prog[pos].LAST := current_day;
				21:	(* event on last day of month *)
					qn[channel] := (DT_TO_TOD(dtime) >= event.START) AND (DT_TO_TOD(dtime) < event.START + event.DURATION) AND (DT_TO_DATE(DTIME) = MONTH_END(DT_TO_DATE(dtime)));
					prog[pos].LAST := current_day;
				30:	(* yearly event on a specific day specified in day *)
					qn[channel] := (DT_TO_TOD(dtime) >= event.START) AND (DT_TO_TOD(dtime) < event.START + event.DURATION) AND DAY_OF_YEAR(DT_TO_DATE(DTIME)) = BYTE_TO_INT(event.DAY);
					prog[pos].LAST := current_day;
				31:	(* event on last day of year *)
					qn[channel] := (DT_TO_TOD(dtime) >= event.START) AND (DT_TO_TOD(dtime) < event.START + event.DURATION) AND (DT_TO_DATE(DTIME) = YEAR_END(YEAR_OF_DATE(DT_TO_DATE(dtime))));
					prog[pos].LAST := current_day;
				40:	(* event on leap days *)
					qn[channel] := (DT_TO_TOD(dtime) >= event.START) AND (DT_TO_TOD(dtime) < event.START + event.DURATION) AND LEAP_DAY(DT_TO_DATE(dtime));
					prog[pos].LAST := current_day;
				41: (* event on holidays *)
					qn[channel] := (DT_TO_TOD(dtime) >= event.START) AND (DT_TO_TOD(dtime) < event.START + event.DURATION) AND HOLY;
					prog[pos].LAST := current_day;
				42: (* event on holidays and weekends *)
					qn[channel] := (DT_TO_TOD(dtime) >= event.START) AND (DT_TO_TOD(dtime) < event.START + event.DURATION) AND (Holy OR (DAY_OF_WEEK(DT_TO_DATE(dtime)) = 6) OR (DAY_OF_WEEK(DT_TO_DATE(dtime)) = 7));
					prog[pos].LAST := current_day;
				43:	(* event on workdays Mo-FR and no holiday *)
					qn[channel] := (DT_TO_TOD(dtime) >= event.START) AND (DT_TO_TOD(dtime) < event.START + event.DURATION) AND (NOT Holy) AND (DAY_OF_WEEK(DT_TO_DATE(dtime)) < 6);
					prog[pos].LAST := current_day;
				50: (* event after reference time *)
					CASE prog[pos].DAY OF
						0:	tx := tref_0;
						1:	tx := tref_1;
					ELSE
						tx := TOD#00:00;
					END_CASE;
					qn[channel] := (DT_TO_TOD(dtime) >= (tx + TOD_TO_TIME(event.START))) AND (DT_TO_TOD(dtime) < (tx + TOD_TO_TIME(event.START) + event.duration));
					prog[pos].LAST := current_day;
				51:	(* event before reference time *)
					CASE prog[pos].DAY OF
						0:	tx := tref_0;
						1:	tx := tref_1;
					ELSE
						tx := TOD#00:00;
					END_CASE;
					qn[channel] := (DT_TO_TOD(dtime) >= (tx - TOD_TO_TIME(event.START))) AND (DT_TO_TOD(dtime) < (tx - TOD_TO_TIME(event.START) + event.duration));
					prog[pos].LAST := current_day;
				52 : (* enable output at specific time + offset  *)
					CASE prog[pos].DAY OF
						0:	tx := tref_0;
						1:	tx := tref_1;
					ELSE
						tx := TOD#00:00;
					END_CASE;
					IF (DT_TO_TOD(dtime) >= tx + TOD_TO_TIME(event.START)) AND (event.LAST <> current_day) THEN
						qn[channel] := TRUE;
						prog[pos].LAST := current_day;
					END_IF;
				53 : (* disable output at specific time + offset *)
					CASE prog[pos].DAY OF
						0:	tx := tref_0;
						1:	tx := tref_1;
					ELSE
						tx := TOD#00:00;
					END_CASE;
					IF (DT_TO_TOD(dtime) >= tx + TOD_TO_TIME(event.START)) AND (event.LAST <> current_day) THEN
						qn[channel] := FALSE;
						prog[pos].LAST := current_day;
					END_IF;
				54 : (* enable output at specific time - offset  *)
					CASE prog[pos].DAY OF
						0:	tx := tref_0;
						1:	tx := tref_1;
					ELSE
						tx := TOD#00:00;
					END_CASE;
					IF (DT_TO_TOD(dtime) >= tx - TOD_TO_TIME(event.START)) AND (event.LAST <> current_day) THEN
						qn[channel] := TRUE;
						prog[pos].LAST := current_day;
					END_IF;
				55 : (* disable output at specific time - offset *)
					CASE prog[pos].DAY OF
						0:	tx := tref_0;
						1:	tx := tref_1;
					ELSE
						tx := TOD#00:00;
					END_CASE;
					IF (DT_TO_TOD(dtime) >= tx - TOD_TO_TIME(event.START)) AND (event.LAST <> current_day) THEN
						qn[channel] := FALSE;
						prog[pos].LAST := current_day;
					END_IF;
			END_CASE;
		END_IF;
	END_FOR;
END_IF;

(* set the outputs *)
Q0 := ENQ AND (qn[0] AND ((ma[0] AND mask) = ma[0]) OR ((mo[0] AND mask) > 0) OR (man AND MI.0));
Q1 := ENQ AND (qn[1] AND ((ma[1] AND mask) = ma[1]) OR ((mo[1] AND mask) > 1) OR (man AND MI.1));
Q2 := ENQ AND (qn[2] AND ((ma[2] AND mask) = ma[2]) OR ((mo[2] AND mask) > 2) OR (man AND MI.2));
Q3 := ENQ AND (qn[3] AND ((ma[3] AND mask) = ma[3]) OR ((mo[3] AND mask) > 3) OR (man AND MI.3));

(* set status *)
IF NOT enq THEN
	status := 100;
ELSIF man THEN
	status := 101;
ELSE
	status := 102;
END_IF;




